71	// Errors are silently ignored — auto-commit is best-effort.
72	// When a commit lands, the resulting SHA is returned.
73	func (f *CommandFactory) beadAutoCommit(operation string) string {
74		workspaceRoot := f.beadWorkspaceRoot()
75		if workspaceRoot == "" {
76			workspaceRoot = f.WorkingDir
77		}
78	
79		cfg, err := config.LoadWithWorkingDir(workspaceRoot)
80		if err != nil {
81			return ""
82		}
83		if cfg.Git == nil {
84			return ""
85		}
86		acCfg := gitpkg.AutoCommitConfig{
87			AutoCommit:   cfg.Git.AutoCommit,
88			CommitPrefix: cfg.Git.CommitPrefix,
89		}
90		beadsFile := filepath.Join(workspaceRoot, ".ddx", "beads.jsonl")
91		sha, _ := gitpkg.AutoCommit(beadsFile, "beads", operation, acCfg)
92		return sha
