95	func (f *CommandFactory) resolveCommitSHA(commitSHA string) (string, error) {
96		if commitSHA == "" {
97			return "", nil
98		}
99	
100		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
101		defer cancel()
102	
103		repoDir := f.WorkingDir
104		if repoDir == "" {
105			repoDir = "."
106		}
107	
108		if isFullCommitSHA(commitSHA) && !gitpkg.IsRepository(repoDir) {
109			return commitSHA, nil
110		}
111	
112		cmd := gitpkg.Command(ctx, repoDir, "rev-parse", "--verify", commitSHA+"^{commit}")
113		out, err := cmd.Output()
114		if err != nil {
115			return "", fmt.Errorf("git rev-parse %s: %w", commitSHA, err)
116		}
117		return strings.TrimSpace(string(out)), nil
118	}
119	
120	func isFullCommitSHA(commitSHA string) bool {
121		if len(commitSHA) != 40 {
122			return false
123		}
124		for i := 0; i < len(commitSHA); i++ {
125			c := commitSHA[i]
126			if c >= '0' && c <= '9' {
127				continue
128			}
129			if c >= 'a' && c <= 'f' {
130				continue
131			}
132			if c >= 'A' && c <= 'F' {
133				continue
134			}
135			return false
136		}
137		return true
138	}
139	
140	func (f *CommandFactory) resolveClosingCommitSHA(commitSHA string) (string, error) {
141		normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
142		if err != nil {
143			return "", fmt.Errorf("invalid closing_commit_sha %q: %w", commitSHA, err)
144		}
145		if normalizedCommitSHA == "" {
146			return "", fmt.Errorf("invalid closing_commit_sha %q: empty value", commitSHA)
147		}
148		return normalizedCommitSHA, nil
149	}
