152	// only bead tracker state. Closing provenance is suppressed only for pure
153	// tracker backfills that touch .ddx/beads.jsonl and nothing else.
154	func (f *CommandFactory) commitIsMetadataOnlyTrackerBackfill(commitSHA string) bool {
155		if commitSHA == "" {
156			return false
157		}
158	
159		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
160		defer cancel()
161	
162		cmd := gitpkg.Command(ctx, f.WorkingDir, "show", "--pretty=format:", "--name-only", commitSHA)
163		out, err := cmd.Output()
164		if err != nil {
165			return false
166		}
167	
168		for _, line := range strings.Split(string(out), "\n") {
169			path := strings.TrimSpace(line)
170			if path == "" {
171				continue
172			}
173			if path != ".ddx/beads.jsonl" {
174				return false
175			}
176		}
177	
178		return true
179	}
