429	func (f *CommandFactory) newBeadUpdateCommand() *cobra.Command {
430		cmd := &cobra.Command{
431			Use:   "update <id>",
432			Short: "Update a bead",
433			Args:  cobra.ExactArgs(1),
434			RunE: func(cmd *cobra.Command, args []string) error {
435				s := f.beadStore()
436	
437				// --claim and --unclaim use dedicated store methods
438				if claim, _ := cmd.Flags().GetBool("claim"); claim {
439					assignee, _ := cmd.Flags().GetString("assignee")
440					if assignee == "" {
441						assignee = resolveClaimAssignee()
442					}
443					if err := s.Claim(args[0], assignee); err != nil {
444						return err
445					}
446					f.beadAutoCommit("claim " + args[0])
447					return nil
448				}
449				if unclaim, _ := cmd.Flags().GetBool("unclaim"); unclaim {
450					if err := s.Unclaim(args[0]); err != nil {
451						return err
452					}
453					f.beadAutoCommit("unclaim " + args[0])
454					return nil
455				}
456	
457				if unsetFlags, _ := cmd.Flags().GetStringArray("unset"); len(unsetFlags) > 0 {
458					for _, key := range unsetFlags {
459						if isProtectedBeadExtraKey(key) {
460							return fmt.Errorf("cannot unset protected bead field: %s", key)
461						}
462					}
463				}
464	
465				var setFlags []string
466				if rawSetFlags, _ := cmd.Flags().GetStringArray("set"); len(rawSetFlags) > 0 {
467					setFlags = make([]string, 0, len(rawSetFlags))
468					for _, kv := range rawSetFlags {
469						k, v, ok := strings.Cut(kv, "=")
470						if !ok {
471							return fmt.Errorf("--set requires key=value format, got: %s", kv)
472						}
473						if k == "closing_commit_sha" {
474							normalizedCommitSHA, err := f.resolveClosingCommitSHA(v)
475							if err != nil {
476								return err
477							}
478							v = normalizedCommitSHA
479						}
480						setFlags = append(setFlags, k+"="+v)
481					}
482				}
483	
484				if err := s.Update(args[0], func(b *bead.Bead) {
485					if v, _ := cmd.Flags().GetString("title"); cmd.Flags().Changed("title") {
486						b.Title = v
487					}
488					if v, _ := cmd.Flags().GetString("status"); cmd.Flags().Changed("status") {
489						b.Status = v
490					}
491					if v, _ := cmd.Flags().GetInt("priority"); cmd.Flags().Changed("priority") {
492						b.Priority = v
493					}
494					if v, _ := cmd.Flags().GetString("labels"); cmd.Flags().Changed("labels") {
495						if v == "" {
496							b.Labels = []string{}
497						} else {
498							b.Labels = strings.Split(v, ",")
499						}
500					}
501					if v, _ := cmd.Flags().GetString("acceptance"); cmd.Flags().Changed("acceptance") {
502						b.Acceptance = v
503					}
504					if v, _ := cmd.Flags().GetString("assignee"); cmd.Flags().Changed("assignee") {
505						b.Owner = v
506					}
507					if v, _ := cmd.Flags().GetString("parent"); cmd.Flags().Changed("parent") {
508						b.Parent = v
509					}
510					if v, _ := cmd.Flags().GetString("description"); cmd.Flags().Changed("description") {
511						b.Description = v
512					}
513					if v, _ := cmd.Flags().GetString("notes"); cmd.Flags().Changed("notes") {
514						b.Notes = v
515					}
516					if len(setFlags) > 0 {
517						if b.Extra == nil {
518							b.Extra = make(map[string]any)
519						}
520						for _, kv := range setFlags {
521							k, v, ok := strings.Cut(kv, "=")
522							if !ok {
523								continue
524							}
525							// Route known field names to struct fields
526							switch k {
527							case "parent":
528								b.Parent = v
529							case "description":
530								b.Description = v
531							case "notes":
532								b.Notes = v
533							case "acceptance":
534								b.Acceptance = v
535							case "issue_type":
536								b.IssueType = v
537							default:
538								// Parse booleans and numbers for proper typing
539								switch v {
540								case "true":
541									b.Extra[k] = true
542								case "false":
543									b.Extra[k] = false
544								default:
545									b.Extra[k] = v
546								}
547							}
548						}
549					}
550					if unsetFlags, _ := cmd.Flags().GetStringArray("unset"); len(unsetFlags) > 0 {
551						for _, key := range unsetFlags {
552							if b.Extra != nil {
553								delete(b.Extra, key)
554							}
555						}
556					}
557				}); err != nil {
558					return err
559				}
560				f.beadAutoCommit("update " + args[0])
561				return nil
562			},
563		}
564	
565		cmd.Flags().String("title", "", "New title")
566		cmd.Flags().String("status", "", "New status (open, in_progress, closed)")
567		cmd.Flags().Int("priority", 0, "New priority")
568		cmd.Flags().String("labels", "", "New labels (comma-separated)")
569		cmd.Flags().String("acceptance", "", "New acceptance criteria")
570		cmd.Flags().String("assignee", "", "New assignee or claim assignee fallback")
571		cmd.Flags().String("parent", "", "New parent bead ID")
572		cmd.Flags().String("description", "", "New description")
573		cmd.Flags().String("notes", "", "New notes")
574		cmd.Flags().Bool("claim", false, "Claim: set status=in_progress, assignee=ddx")
575		cmd.Flags().Bool("unclaim", false, "Unclaim: set status=open, clear assignee and claim fields")
576		cmd.Flags().StringArray("set", nil, "Set custom field (key=value, repeatable)")
577		cmd.Flags().StringArray("unset", nil, "Unset custom field (key repeatable)")
578	
579		return cmd
580	}
