765		// Defense in depth: cap every event body regardless of caller. The
766		// reviewer write path separately persists the full stream to an artifact
767		// and emits a <=512-byte body; this cap catches anything else.
768		event.Body = capFieldBytes(event.Body)
769		event.Summary = capFieldBytes(event.Summary)
770		return s.Update(id, func(b *Bead) {
771			if b.Extra == nil {
