107	// formatCountMap renders a map[string]int as "key1(n) key2(n) ..." sorted by count desc.
108	func formatCountMap(m map[string]int) string {
109		if len(m) == 0 {
110			return "(none)"
111		}
112		// Build sorted slice: highest count first, then lexicographic.
113		type kv struct {
114			k string
115			v int
116		}
117		pairs := make([]kv, 0, len(m))
118		for k, v := range m {
119			pairs = append(pairs, kv{k, v})
120		}
121		for i := 0; i < len(pairs); i++ {
122			for j := i + 1; j < len(pairs); j++ {
123				if pairs[j].v > pairs[i].v || (pairs[j].v == pairs[i].v && pairs[j].k < pairs[i].k) {
124					pairs[i], pairs[j] = pairs[j], pairs[i]
125				}
126			}
127		}
128		out := ""
129		for _, p := range pairs {
130			if out != "" {
131				out += " "
132			}
133			out += fmt.Sprintf("%s(%d)", p.k, p.v)
134		}
135		return out
136	}
